def can_pay_remainder(r, c1, c2):
    # Can we pay exactly r with at most c1 ones and c2 twos?
    if r < 0:
        return False
    # Try all x2 from 0 to min(c2, r//2)
    for x2 in range(min(c2, r // 2) + 1):
        rem = r - 2 * x2
        if rem <= c1:
            return True
    return False

def min_c3_for_amount(a, c1, c2):
    # minimum x3 needed to pay a with given c1, c2
    # x3 >= ceil((a - c1 - 2*c2) / 3)
    min_x3 = max(0, -(-( a - c1 - 2*c2) // 3))  # ceil
    # But we need to find smallest x3 >= min_x3 such that (a - 3*x3) is payable
    # a - 3*x3 must be in [0, c1+2*c2] and achievable
    for x3 in range(min_x3, min_x3 + 3):
        r = a - 3 * x3
        if 0 <= r <= c1 + 2 * c2 and can_pay_remainder(r, c1, c2):
            return x3
    return float('inf')

import sys
input_data = sys.stdin.read().split()
idx = 0
t = int(input_data[idx]); idx += 1
for _ in range(t):
    n = int(input_data[idx]); idx += 1
    a = [int(input_data[idx+i]) for i in range(n)]
    idx += n

    best = float('inf')
    for c1 in range(3):
        for c2 in range(3):
            # find min c3 needed
            c3 = 0
            ok = True
            for ai in a:
                needed = min_c3_for_amount(ai, c1, c2)
                if needed == float('inf'):
                    ok = False
                    break
                c3 = max(c3, needed)
            if ok:
                best = min(best, c1 + c2 + c3)
    print(best)
